INSERT INTO jobs (id, profile_id, title, company_id, location_id, url, source_id, description, hash, scraped_at, score, score_reasoning) VALUES (1, 1, 'AI/ML Engineer', 2, 1, 'https://www.adzuna.com/jobs/view/kavak-ai-ml-engineer-001', 1, 'Kavak is looking for an AI/ML Engineer to join our team in CDMX. You will work on developing and deploying machine learning models at scale, with a focus on LLMs and recommendation systems. Proficiency in Python and PyTorch is required. Experience with RAG pipelines and fine-tuning is a plus.', 'kavak-aiml-hash-001', '2026-06-15 23:08:34', 88, 'Strong match for AI Engineer profile (score: 88/100). All core keywords found: Python, PyTorch, LLM. Relevant experience with ML models at scale. Salary range likely aligns with 60k+ MXN.');
INSERT INTO jobs (id, profile_id, title, company_id, location_id, url, source_id, description, hash, scraped_at, score, score_reasoning) VALUES (2, 2, 'Senior Fullstack Engineer', 3, 2, 'https://remotive.com/remote-jobs/globant-senior-fullstack-002', 2, 'Globant is seeking a Senior Fullstack Engineer to work from our Guadalajara office in a hybrid model. You will build modern web applications using React, TypeScript, and Node.js. Experience with PostgreSQL, REST API design, and Next.js is highly valued. You will collaborate with cross-functional teams across Latin America.', 'globant-fullstack-hash-002', '2026-06-17 23:08:34', 82, 'Good match for Senior Fullstack Engineer profile (score: 82/100). Keywords found: React, TypeScript, REST API, PostgreSQL. Hybrid model in GDL aligns with location preference.');
